syntax = "proto3";

message Person {
  string name = 1;
  int32 id = 2;
  string email = 3;

  enum PhoneType {
    MOBILE = 0;
    HOME = 1;
    WORK = 2;
  }

  message PhoneNumber {
    string number = 1;
    PhoneType type = 2;
  }

  repeated PhoneNumber phones = 4;
}
# Gerekli kütüphaneyi yükleyin:
# pip install protobuf

# 'person.proto' dosyasından Python sınıfını oluşturmak için komut satırında şunu çalıştırın:
# protoc --python_out=. person.proto
# Bu komut 'person_pb2.py' adında bir dosya oluşturacaktır.

import person_pb2

# Yeni bir Person mesajı oluştur
person = person_pb2.Person()
person.name = "Alice"
person.id = 123
person.email = "alice@example.com"

# Bir telefon numarası ekle
phone1 = person.phones.add()
phone1.number = "555-1234"
phone1.type = person_pb2.Person.PhoneType.MOBILE

# Başka bir telefon numarası ekle
phone2 = person.phones.add()
phone2.number = "555-5678"
phone2.type = person_pb2.Person.PhoneType.HOME

print("Orijinal Person objesi:")
print(f"İsim: {person.name}")
print(f"ID: {person.id}")
print(f"Email: {person.email}")
for p in person.phones:
    print(f"  Telefon: {p.number} ({person_pb2.Person.PhoneType.Name(p.type)})")

# Mesajı bir byte dizisine serileştir (paketle)
serialized_data = person.SerializeToString()

print("\nSerileştirilmiş veri (bytes):", serialized_data)

# Byte dizisinden mesajı serileştirmeden çıkar (aç)
new_person = person_pb2.Person()
new_person.ParseFromString(serialized_data)

print("\nSerileştirmeden çıkarılan (Deserialized) Person objesi:")
print(f"İsim: {new_person.name}")
print(f"ID: {new_person.id}")
print(f"Email: {new_person.email}")
for p in new_person.phones:
    print(f"  Telefon: {p.number} ({person_pb2.Person.PhoneType.Name(p.type)})")
